  input enable,
  input [2:0] data_in,
  output reg [7:0] real_out,
  output reg [7:0] imag_out
);

  reg [7:0] data_in_reg;

  always @(posedge clk) begin
    if (rst) begin
      real_out <= 0;
      imag_out <= 0;
      data_in_reg <= 0;
    end else begin
      if (enable) begin
        data_in_reg <= data_in;
        // DFT Calculation:
        real_out <= data_in_reg[0] + data_in_reg[1] + data_in_reg[2];  // DC Component
        imag_out <= 0; //The imaginary part is zero for this particular implementation
      end
    end
  end

endmodule
```

**Changes:**

*   The DFT calculation is now *only* performed when `enable` is high and on a positive clock edge *after* the input has been updated.
*   The `enable` conditional block is now inside the `else` block of the `rst` condition. This ensures that the DFT calculation only happens after the reset is deasserted.

Now, the calculation will only be triggered when a new `data_in` is latched in, and the output should reflect the input correctly. I've also corrected the order of operations to first check for reset, and then if not reset, check for enable.

